#include <stdio.h>
#include <stdbool.h>

bool isPrime[1001];

void sieve() {
    for (int i = 0; i <= 1000; i++) isPrime[i] = true;
    isPrime[0] = isPrime[1] = false;
    for (int p = 2; p * p <= 1000; p++) if (isPrime[p]) for (int q = p * p; q <= 1000; q += p) isPrime[q] = false;
}

int main() {
    sieve();
    int L, R; scanf("%d %d", &L, &R);
    bool first = true;
    for (int i = L; i <= R; i++) if (isPrime[i]) {
        if (!first) printf(" ");
        printf("%d", i);
        first = false;
    }
    if (first) printf("");
    printf("\n");
    return 0;
}

