#include <bits/stdc++.h>
using namespace std;

const int MAX = 1000;
bool prime[MAX + 1];

void sieve() {
    fill(prime, prime + MAX + 1, true);
    prime[0] = prime[1] = false;
    for (int p = 2; p * p <= MAX; p++) if (prime[p]) for (int q = p * p; q <= MAX; q += p) prime[q] = false;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(NULL);
    sieve();
    int L, R; cin >> L >> R;
    bool first = true;
    for (int i = L; i <= R; i++) if (prime[i]) {
        if (!first) cout << ' ';
        cout << i;
        first = false;
    }
    if (first) cout << "";
    cout << "\n";
    return 0;
}

