        prime[0] = prime[1] = false;
        for (int p = 2; p * p <= MAX; p++) if (prime[p]) for (int q = p * p; q <= MAX; q += p) prime[q] = false;
        StringBuilder out = new StringBuilder();
        boolean first = true;
        for (int i = L; i <= R; i++) if (prime[i]) {
            if (!first) out.append(' ');
            out.append(i);
            first = false;
        }
        if (first) out.append("");
        System.out.print(out.toString());
    }
}

