import sys

def sieve(limit):
    prime = [True] * (limit + 1)
    prime[0] = prime[1] = False
    for p in range(2, int(limit ** 0.5) + 1):
        if prime[p]:
            for q in range(p * p, limit + 1, p):
                prime[q] = False
    return prime

prime = sieve(1000)

L, R = map(int, sys.stdin.readline().split())
line = [str(i) for i in range(L, R + 1) if prime[i]]
print(' '.join(line) if line else '')

